function i(){const o=document.querySelectorAll('input[type="file"][name="wheel_photos[]"]');o.length&&o.forEach(e=>{const t=e.closest("form")?.querySelector(".file-list");t&&e.addEventListener("change",()=>{t.innerHTML="",e.files.length&&Array.from(e.files).forEach(r=>{const n=document.createElement("div");n.className="file-item",n.textContent=r.name,t.appendChild(n)})})})}export{i as initUploadPhotos};
